name: spec-driven-app

services:
  dev:
    profiles: ["dev"]
    build:
      context: .
      dockerfile: .devcontainer/Dockerfile
    volumes:
      - .:/workspaces/repo:cached
    working_dir: /workspaces/repo
    command: sleep infinity
    ports:
      - "3000:3000"
      - "3001:3001"
    environment:
      - NODE_ENV=development
    depends_on:
      - postgres-dev
      - redis-dev
      - keycloak-dev
      - minio-dev
      - minio-mc-dev

